t.script:
// Estado interno de la venta
let ventaData = {
    cliente_id: null,
    lineas: [],
    journal_id: null
};

// Productos disponibles (para búsqueda rápida)
const productosData = [

        { id: , name: "", price: , stock: , isService:  },

];

// ╔════════════════════════════════════════════════════════════╗
// ║ AUTOCOMPLETE DE CLIENTES - Búsqueda en tiempo real       ║
// ╚════════════════════════════════════════════════════════════╝

let clienteSearchTimer = null;
let clienteActiveIndex = -1;
let clienteResults = [];

// Al cargar la página, traer los primeros clientes automáticamente
document.addEventListener('DOMContentLoaded', function() {
    buscarClientes('');
});

const clienteInput = document.getElementById('clienteSearchInput');
const clienteDropdown = document.getElementById('clienteDropdown');
const clienteHidden = document.getElementById('clienteSelectValue');
const clienteContainer = document.getElementById('clienteAutocomplete');

// Input: búsqueda con debounce
clienteInput.addEventListener('input', function() {
    const term = this.value.trim();

    // Si ya había un cliente seleccionado y el usuario borra, limpiar selección
    if (ventaData.cliente_id) {
        ventaData.cliente_id = null;
        clienteHidden.value = '';
        clienteContainer.classList.remove('has-selection');
        clienteInput.classList.remove('has-value');
        document.getElementById('clienteInfo').style.display = 'none';
    }

    clearTimeout(clienteSearchTimer);
    clienteSearchTimer = setTimeout(function() {
        buscarClientes(term);
    }, 300);
});

// Focus: mostrar dropdown con resultados
clienteInput.addEventListener('focus', function() {
    if (!ventaData.cliente_id) {
        if (clienteResults.length > 0) {
            clienteDropdown.classList.add('show');
        } else {
            buscarClientes(this.value.trim());
        }
    }
});

// Click fuera: cerrar dropdown
document.addEventListener('click', function(e) {
    if (!clienteContainer.contains(e.target)) {
        clienteDropdown.classList.remove('show');
        clienteActiveIndex = -1;
    }
});

// Teclado: navegar con flechas y Enter
clienteInput.addEventListener('keydown', function(e) {
    const items = clienteDropdown.querySelectorAll('.nv-autocomplete-item');
    if (!items.length) return;

    if (e.key === 'ArrowDown') {
        e.preventDefault();
        clienteActiveIndex = Math.min(clienteActiveIndex + 1, items.length - 1);
        actualizarItemActivo(items);
    } else if (e.key === 'ArrowUp') {
        e.preventDefault();
        clienteActiveIndex = Math.max(clienteActiveIndex - 1, 0);
        actualizarItemActivo(items);
    } else if (e.key === 'Enter') {
        e.preventDefault();
        if (clienteActiveIndex >= 0 && clienteActiveIndex < items.length) {
            items[clienteActiveIndex].click();
        }
    } else if (e.key === 'Escape') {
        clienteDropdown.classList.remove('show');
        clienteActiveIndex = -1;
    }
});

function actualizarItemActivo(items) {
    items.forEach(function(item, i) {
        if (i === clienteActiveIndex) {
            item.classList.add('active');
            item.scrollIntoView({ block: 'nearest' });
        } else {
            item.classList.remove('active');
        }
    });
}

function buscarClientes(term) {
    // Mostrar loading
    clienteDropdown.innerHTML = '<div class="nv-autocomplete-loading">⏳ Buscando clientes...</div>';
    clienteDropdown.classList.add('show');
    clienteActiveIndex = -1;

    fetch('/ventas/buscar_clientes', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            jsonrpc: "2.0",
            method: "call",
            params: { term: term, limit: 30 }
        })
    })
    .then(function(r) { return r.json(); })
    .then(function(data) {
        if (data.result && data.result.success) {
            clienteResults = data.result.clientes;
            renderizarClientes(data.result.clientes, data.result.total);
        } else {
            clienteDropdown.innerHTML = '<div class="nv-autocomplete-empty">❌ Error al buscar clientes</div>';
        }
    })
    .catch(function() {
        clienteDropdown.innerHTML = '<div class="nv-autocomplete-empty">❌ Error de conexión</div>';
    });
}

function renderizarClientes(clientes, total) {
    if (clientes.length === 0) {
        clienteDropdown.innerHTML = '<div class="nv-autocomplete-empty">No se encontraron clientes</div>';
        return;
    }

    let html = '';
    var dq = String.fromCharCode(34);
    clientes.forEach(function(c) {
        var safeLabel = c.label.replace(new RegExp(dq, 'g'), '&apos;');
        html += '<div class=' + dq + 'nv-autocomplete-item' + dq + ' data-id=' + dq + c.id + dq + ' data-label=' + dq + safeLabel + dq + ' onclick=' + dq + 'seleccionarCliente(' + c.id + ', this)' + dq + '>';
        html += '<span class=' + dq + 'nv-ac-icon' + dq + '>👤</span>';
        html += '<span class=' + dq + 'nv-ac-name' + dq + '>' + c.name + '</span>';
        if (c.vat) {
            html += '<span class=' + dq + 'nv-ac-vat' + dq + '>' + c.vat + '</span>';
        }
        html += '</div>';
    });

    if (total > clientes.length) {
        html += '<div class="nv-autocomplete-info">Mostrando ' + clientes.length + ' de ' + total + ' — Escribí para filtrar</div>';
    }

    clienteDropdown.innerHTML = html;
}

function seleccionarCliente(id, elem) {
    const label = elem.getAttribute('data-label');
    ventaData.cliente_id = id;
    clienteHidden.value = id;
    clienteInput.value = label;
    clienteInput.classList.add('has-value');
    clienteContainer.classList.add('has-selection');
    clienteDropdown.classList.remove('show');
    clienteActiveIndex = -1;

    // Mostrar info de cliente seleccionado
    document.getElementById('clienteInfo').style.display = 'block';
    document.getElementById('clienteInfoNombre').innerText = label;

    actualizarResumen();
}

function limpiarCliente() {
    ventaData.cliente_id = null;
    clienteHidden.value = '';
    clienteInput.value = '';
    clienteInput.classList.remove('has-value');
    clienteContainer.classList.remove('has-selection');
    document.getElementById('clienteInfo').style.display = 'none';
    clienteActiveIndex = -1;
    clienteResults = [];
    actualizarResumen();
    clienteInput.focus();
    buscarClientes('');
}

function crearClienteRapido() {
    const nombre = document.getElementById('nuevoClienteNombre').value.trim();
    const dni = document.getElementById('nuevoClienteDNI').value.trim();

    if (!nombre) {
        alert('Ingresa el nombre del cliente');
        return;
    }

    fetch('/ventas/crear_cliente', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            jsonrpc: "2.0",
            method: "call",
            params: { nombre: nombre, dni: dni }
        })
    })
    .then(function(r) { return r.json(); })
    .then(function(data) {
        if (data.result && data.result.success) {
            // Seleccionar el nuevo cliente automáticamente
            ventaData.cliente_id = data.result.id;
            clienteHidden.value = data.result.id;
            clienteInput.value = data.result.nombre;
            clienteInput.classList.add('has-value');
            clienteContainer.classList.add('has-selection');

            // Limpiar formulario
            document.getElementById('nuevoClienteNombre').value = '';
            document.getElementById('nuevoClienteDNI').value = '';
            document.getElementById('nuevoClienteForm').classList.remove('show');

            // Mostrar info
            document.getElementById('clienteInfo').style.display = 'block';
            document.getElementById('clienteInfoNombre').innerText = data.result.nombre;

            actualizarResumen();
            alert(data.result.message);
        } else {
            alert('Error: ' + (data.result ? data.result.message : 'Unknown'));
        }
    })
    .catch(function(err) {
        console.error(err);
        alert('Error de conexión');
    });
}

function agregarProducto() {
    const select = document.getElementById('productoSelect');
    const cantidad = parseFloat(document.getElementById('productoCantidad').value);

    if (!select.value) {
        alert('Selecciona un producto');
        return;
    }

    if (cantidad <= 0) {
        alert('La cantidad debe ser mayor a 0');
        return;
    }

    const productId = parseInt(select.value);
    const producto = productosData.find(p => p.id === productId);

    if (!producto) {
        alert('Producto no encontrado');
        return;
    }

    // ╔════════════════════════════════════════════════════════════╗
    // ║ VALIDACIÓN DE STOCK - BLINDAJE CONTRA SOBREVENTA          ║
    // ╚════════════════════════════════════════════════════════════╝
    if (!producto.isService) {
        // Solo validar stock si NO es un servicio
        const stockDisponible = parseFloat(select.options[select.selectedIndex].getAttribute('data-stock')) || 0;

        if (cantidad > stockDisponible) {
            alert('La cantidad a vender debe ser igual o menor a ' + stockDisponible.toFixed(0) + ' u.');
            return;
        }
    }

    // Crear línea
    const linea = {
        id: Date.now(),
        product_id: producto.id,
        product_name: producto.name,
        quantity: cantidad,
        price_unit: producto.price,
        subtotal: cantidad * producto.price
    };

    ventaData.lineas.push(linea);

    // Limpiar selects
    select.value = '';
    document.getElementById('productoCantidad').value = '1';

    actualizarVistaLineas();
    actualizarResumen();
}

function eliminarLinea(id) {
    ventaData.lineas = ventaData.lineas.filter(l => l.id !== id);
    actualizarVistaLineas();
    actualizarResumen();
}

function actualizarVistaLineas() {
    const container = document.getElementById('lineasProductos');

    if (ventaData.lineas.length === 0) {
        container.innerHTML = '<p class="text-muted text-center py-4">No hay productos agregados aún</p>';
        return;
    }

    container.innerHTML = ventaData.lineas.map(linea => `
        <div class="nv-linea">
            <div class="nv-linea-header">
                <div class="nv-linea-producto">${linea.product_name}</div>
                <div class="nv-linea-close" onclick="eliminarLinea(${linea.id})">✕</div>
            </div>
            <div class="nv-linea-totales">
                <div class="nv-linea-total-item">
                    <div class="nv-linea-total-label">Cantidad</div>
                    <div class="nv-linea-total-value">${linea.quantity.toFixed(2)}</div>
                </div>
                <div class="nv-linea-total-item">
                    <div class="nv-linea-total-label">Precio Unit.</div>
                    <div class="nv-linea-total-value">$${linea.price_unit.toFixed(2)}</div>
                </div>
                <div class="nv-linea-total-item">
                    <div class="nv-linea-total-label">Subtotal</div>
                    <div class="nv-linea-total-value">$${linea.subtotal.toFixed(2)}</div>
                </div>
            </div>
        </div>
    `).join('');
}

function actualizarResumen() {
    const cantProductos = ventaData.lineas.length;
    const cantTotal = ventaData.lineas.reduce((sum, l) => sum + l.quantity, 0);
    const total = ventaData.lineas.reduce((sum, l) => sum + l.subtotal, 0);

    document.getElementById('resumenCantProductos').innerText = cantProductos;
    document.getElementById('resumenCantTotal').innerText = cantTotal.toFixed(2);
    document.getElementById('resumenTotal').innerText = '$' + total.toFixed(2);

    const resumen = document.getElementById('resumenTotales');
    if (cantProductos > 0) {
        resumen.style.display = 'block';
    } else {
        resumen.style.display = 'none';
    }
}

function guardarVenta() {
    // Validaciones
    if (!ventaData.cliente_id) {
        alert('Selecciona un cliente');
        return;
    }

    if (ventaData.lineas.length === 0) {
        alert('Agrega al menos un producto');
        return;
    }

    // Validar método de pago obligatorio
    const paymentSelect = document.getElementById('paymentMethodSelect');
    if (!paymentSelect.value) {
        alert('Selecciona un método de pago');
        paymentSelect.focus();
        return;
    }

    const btn = event.target;
    const txtBtn = btn.innerText;
    btn.disabled = true;
    btn.innerHTML = '<span class="nv-spinner" style="margin-right: 0.5rem;"></span> Procesando...';

    // Convertir lineas al formato esperado
    const lineas = ventaData.lineas.map(l => ({
        product_id: l.product_id,
        quantity: l.quantity
    }));

    // Llamada AJAX
    fetch('/ventas/crear', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            jsonrpc: "2.0",
            method: "call",
            params: {
                cliente_id: ventaData.cliente_id,
                lineas: lineas,
                origen: 'admin',
                journal_id: ventaData.journal_id
            }
        })
    })
    .then(r => r.json())
    .then(data => {
        if (data.result && data.result.success) {
            alert(data.result.message);
            window.location.href = data.result.url || '/ventas';
        } else {
            alert('Error: ' + (data.result ? data.result.message : 'Unknown'));
            btn.disabled = false;
            btn.innerText = txtBtn;
        }
    })
    .catch(err => {
        console.error(err);
        alert('Error de conexión');
        btn.disabled = false;
        btn.innerText = txtBtn;
    });
}

// Inicializar resumen
actualizarResumen();

// Escucha cambios en el método de pago
document.getElementById('paymentMethodSelect').addEventListener('change', function() {
    const val = this.value;
    if (!val) {
        ventaData.journal_id = null;
    } else if (!isNaN(val)) {
        ventaData.journal_id = parseInt(val);
    } else {
        ventaData.journal_id = val; // valor estético (string)
    }
});
